import{_ as e,c as t,o as p,ae as r}from"./chunks/framework.BvcDoAct.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ja-jp/Management2/PART2/2.md","filePath":"ja-jp/Management2/PART2/2.md"}'),o={name:"ja-jp/Management2/PART2/2.md"};function n(s,a,i,l,h,d){return p(),t("div",null,[...a[0]||(a[0]=[r('<p>► 2022/12</p><h2 id="ビジネス系メディアの取材を通じて感じた自信と確信" tabindex="-1">ビジネス系メディアの取材を通じて感じた自信と確信 <a class="header-anchor" href="#ビジネス系メディアの取材を通じて感じた自信と確信" aria-label="Permalink to &quot;ビジネス系メディアの取材を通じて感じた自信と確信&quot;">​</a></h2><p>#リーダーシップ #変革 #自信 #確信</p><h3 id="「-救世主-が必要なほど日本経済や音楽業界が弱っていることが明白だったことも、結果としてはbmsgの後押しをしてくれた」から" tabindex="-1">「“救世主”が必要なほど日本経済や音楽業界が弱っていることが明白だったことも、結果としてはBMSGの後押しをしてくれた」から <a class="header-anchor" href="#「-救世主-が必要なほど日本経済や音楽業界が弱っていることが明白だったことも、結果としてはbmsgの後押しをしてくれた」から" aria-label="Permalink to &quot;「“救世主”が必要なほど日本経済や音楽業界が弱っていることが明白だったことも、結果としてはBMSGの後押しをしてくれた」から&quot;">​</a></h3><p><strong>2023年がいよいよ始まった。新しい年は、BMSGおよびSKY-HIにとってどんな1年となるのだろうか。1月13日からはBMSGの新しいボーイズグループ「MAZZEL(マーゼル)」の誕生までに迫るオーディションドキュメンタリー番組『MISSIONx2(ミッション・ミッション)』の配信がYouTubeで始まり、今春にはMAZZELがデビュー。所属アーティストの挑戦もますます積極的に進められることだろう。</strong></p><p><strong>オーディション「THEFIRST」での参加者の導き方やそこで語られる信念、はたまたそこからデビューしたBE:FIRSTを人気アーティストに育て上げた手腕などでも、今、SKY-HIは世の注目を集めている。最も勢いのあるマネジメントレーベルBMSGを率いる立場として、特にここ1年はビジネス系メディアから「新しいリーダー」「音楽業界の革命児」として、取材を受けることも増えてきた。これまでのアーティストとしてとは違う角度からの取材を通して、感じたこともいろいろあったという。</strong></p><p>『日経エンタ!』さんの場合は、(「THE FIRST」が始まる)初期すぎる段階から見てくれていたので少し違うかもしれませんが、ビジネス系媒体の方々の取材を受けて強く感じた1つは、「新時代のリーダー」「新時代のマネジメント術」を常に探していらっしゃるんだなということです。</p><p>エンタテインメントに限らず、政治や経済、スポーツなどあらゆる分野で、世の中は常に“救世主”を探していますよね。その期待に応えるための作業を考えると、サッカーにたとえるならば、「ゴール前でいいパスをもらえるために走る」ことが、成功のためには必要だと思います。</p><p>でも、ゴールに向かって闇雲に走るだけではディフェンダーもついてきてしまうし、良いパスは飛んでこないじゃないですか。だから、センスや経験を生かしてゴール前に走れる人になる必要もあるし、それができればパスはおのずと回ってきてしまう。</p><p>逆に言えば、自分にパスする人がいなくなったり移籍したりしたら・・・この場合、環境が変わったりしたら活躍できない選手になってしまうのは大きな問題。だから、自分でゲームを作れて、チームの士気も上げられて、なんなら試合に出なくても概念を浸透させてチームを勝たせられるような人間に、最終的にはなっていく必要があるのかなとすごく感じています。</p><p>世の中が、新時代のリーダーなり救世主なりを探していることと、自分が今こうして動いていることがハモったのかなと少し感じましたし、それはより加速させていかなくてはいけないと思いました。</p><h3 id="反響から得た「自信」と「確信」" tabindex="-1">反響から得た「自信」と「確信」 <a class="header-anchor" href="#反響から得た「自信」と「確信」" aria-label="Permalink to &quot;反響から得た「自信」と「確信」&quot;">​</a></h3><p>ビジネス系媒体の取材でもう1つ驚いたのは、音楽業界の「普通」は、本当に世の中に知られていないということでした。</p><p>自分はアーティストという特異で浮世離れした世界に生きる人間ではありますが、一般社会に生きる人間としての感覚で、アーティストやアイドル業界の在り方やビジネスモデルに対しておかしいと感じていたのです。でも、音楽界の方は「そういうもの」とそれを普通に思っているようだし、いわゆる誰かのファンをやっている方々もどうしてそれに違和感を覚えないのだろうかと不思議に思っていたんです。いざ、ビジネス系の媒体の方々に「アーティストやアイドルはこんなビジネスモデルなんです」と20年来の音楽界の常識を話すだけでもやはり驚かれるんです。それに対して問題意識を抱えているという話をするだけで記事が成立してしまい、その週に1番読まれた記事に毎回挙がるくらいの賛同や反響があった。でも、それは起業当初から持っていた部分であって、それが反響を得たことは、自分の社会人意識の成長や自分の強みの認識につながったことでもありました。</p><p>自分がやっていること、やろうとしていることは間違いじゃないという自信や確信にもつながったし、改めて業界の危機感も感じられました。あとは、その“救世主”が必要なほど、日本経済や音楽業界が弱っていることが明白だったことも、結果としてはBMSGの後押しをしてくれたかなと思ってます。今はようやく「経営者」として会社をPRしていかなくてはいけないという課題に足を踏み入れられたかなと思っています。</p><h3 id="「新しいリーダー」として神輿に乗る覚悟" tabindex="-1">「新しいリーダー」として神輿に乗る覚悟 <a class="header-anchor" href="#「新しいリーダー」として神輿に乗る覚悟" aria-label="Permalink to &quot;「新しいリーダー」として神輿に乗る覚悟&quot;">​</a></h3><p><strong>「新時代のリーダー」としてメディア側に担がれることに対し、戸惑いなどは感じていなかったのだろうか。そう尋ねると、「その覚悟も、ひょっとしたら最近できたような気がします」との答えが返ってきた。</strong></p><p>自分がBMSG設立時に掲げたビジョンを達成するためには、ただ「アーティストが売れる」というだけではなく、「BMSGが影響力を持つ」ことが必要です。ビジネス系媒体の取材記事の反響が広がるほど、そこにもつながっていくのかなと思います。だから自分は覚悟を持って、担がれた神輿に乗っていく必要があると考えています。神輿に乗れば落ちる危険性もあるし、石を投げられたときも1番目立つところにいるわけで、当然「怖いな」と感じるところもあります。でも、BEFIRSTを神輿に乗せるわけには絶対にいかないし、それこそ何かあったら、たとえ彼らの責任であっても顔向けできないですから。</p><p>僕は「アーティストを守る」っていう言葉が好きではなく、その言葉に違和感を感じているんです。ただ、僕がアーティストに望んでいる「心身共に健康な成長」のためには、向こう何年かは、自分が精一杯体を張って先頭に立つ覚悟は必要だと強く思ってます。</p><p>今、起業当初に言っていたことが1つずつ顕在化していることに、ものすごくモメンタム(勢い、盛り上がり)を感じているところがあります。例えば、アーティストとして自分らしく活動する際の障壁が表面化したり、BE:FIRSTとINIのようにアーティスト同士のコラボが増えたり、紅白歌合戦やレコード大賞などに出場出演するラインアップが変わったり。まことしやかにささやかれてきた「枠」が崩れている。僕は今、芸能の世界が明確に変わってきたと認識していて、今後はさらに長年の問題がより表面化していくと思うんです。そこにモメンタムを感じます。モメンタムって、Twitter上で更新されていた『100話で心折れるスタートアップ』を読んでから気に入って使っているんですが、そうした使いたくなる用語を無邪気に楽しめる精神状態にはなりましたね(笑)。</p><h3 id="数え切れないほどの「最高の瞬間」" tabindex="-1">数え切れないほどの「最高の瞬間」 <a class="header-anchor" href="#数え切れないほどの「最高の瞬間」" aria-label="Permalink to &quot;数え切れないほどの「最高の瞬間」&quot;">​</a></h3><p><strong>道なき道を猛スピードで進むなか、率いる立場としての孤独は「今は感じる暇がない」と笑った。最後に、BMSGを立ち上げてから最も幸せを感じた瞬間を聞いた。</strong></p><p>「わあ、いっぱいあるなあ。今はBE:FIRSTのツアー全公演を通してずっと思っているし、MAZZELのリハーサル中もいつも思うし、(トレーニーの)RUIとTAIKIがディズニーランドへ行った写真を送ってくれたときも幸せだったし。</p><p>あと、21年12月12日、僕の誕生日にスタッフと所属アーティストが一緒になって、すごく手の込んだ“お誕生日おめでとう動画”を送ってくれたときに、ものすごく幸せを感じたのを今でもはっきり覚えてますね。ちょうど21年11月が会社として1番の危機だったんですが、それを乗り越えての時期だったこともあり。</p><p>幸せな瞬間は、挙げるとキリがないかもしれない(笑)。うん、本当にめちゃくちゃいっぱいある!</p>',25)])])}const _=e(o,[["render",n]]);export{c as __pageData,_ as default};
